class DataHandler {
public:
    DataHandler(const std::vector<int>& data) : data_(data) {
        calculateFrequency();
    }

    int search() {
        int result = -1;
        for (const auto& entry : frequency_) {
            if (entry.first <= entry.second) {
                result = std::max(result, entry.first);
            }
        }
        return result;
    }

private:
    std::vector<int> data_;
    std::unordered_map<int, int> frequency_;

    void calculateFrequency() {
        for (int num : data_) {
            frequency_[num]++;
        }
    }
};
